// Se obtiene la lista de items de entrada
const items = $input.all();

const outputItems = items.map(item => {
  // Se asume que el nombre del archivo viene en item.json.nombre
  const fileName = item.json.nombre;

  // Expresión regular para extraer dígitos entre guiones bajos: _número_
  const regex = /_(\d+)_/;
  const match = fileName.match(regex);

  if (!match) {
    // Si no se encuentra el patrón, se retorna un error en el item
    return { json: { error: `No se encontró el número en el nombre: ${fileName}` } };
  }

  // El primer grupo capturado es el número
  const extractedNumber = match[1];

  // Mapeo de números a nombres según la tabla proporcionada
  const mapping = {
    "101": "Miguel Moreno",
    "250": "Cesar Hernandez",
    "290": "Dorvelis Pineda",
    "299": "IVR Menu 1",
    "300": "Setters",
    "301": "Ana Karina Kristen",
    "302": "Carlos Perez",
    "303": "Nora castillo",
    "304": "Lorraine Atencio",
    "308": "Yelitza castillo",
    "310": "Nordelys Rodriguiez",
    "350": "Carlen Gonzalez",
    "351": "Yonmar Gonzalez",
    "352": "Carolina Santana",
    "353": "Paola Medina",
    "355": "Francelis Sanchez",
    "356": "Juan Raúl Martínez",
    "391": "Ridchell Ladera",
    "399": "Patricia Medina",
    "401": "Andrea P",
    "402": "David F",
    "403": "Diego Delgado",
    "450": "Leopoldo Aponte",
    "499": "Customer Experience",
    "501": "Glendy Aguil",
    "961": "genesis carbone"
  };

  // Se obtiene el nombre correspondiente al número extraído. 
  // Si no se encuentra, se asigna "Nombre no encontrado".
  const nombreCorrespondiente = mapping[extractedNumber] || "Nombre no encontrado";

  // Se retorna el item con el resultado deseado
  return { 
    json: { 
      fileName,
      extractedNumber,
      nombreCorrespondiente 
    } 
  };
});

// Se retorna el array de items resultantes
return outputItems;

// Configuración de campos personalizados con IDs
const CUSTOM_FIELDS = {
  transcripcion: "c24a78eb-3a4a-4c5b-ad70-37d58070ea6b",
  puntuacion: "ce738bf2-9e6f-4513-ae9f-58a64c1ad72d",
  puntos_fuertes: "48e36e25-2d35-4604-bb66-7adcfd684fa3",
  puntos_debiles: "b7ae3718-29f4-4102-92be-3e10e97ea155",
  recomendaciones: "1574ba8b-0b95-4a4d-9154-246141b1c2c4",
  faq_objeciones: "e0effb0a-f6e2-48bb-81c0-e94251585462",
  seguimiento: "62c85357-3656-4081-9e01-94fe6cc9f697",
  tipo_llamada: "ad351a2e-0cc7-4b50-8a23-f8747345732f",
  solicitud_referido: "bbab966c-6c9e-40e0-8b2c-5bb985ca9afd",
  asistente: "f15f367f-fc1b-4bdc-ab52-b797a10ffb74",
  promesas_vendedor: "e71fd1e9-2ffb-4199-a697-7fe553f0a136"
};

/**
 * Funciones auxiliares
 */
const Utils = {
  // Sanitiza el texto para ClickUp (convierte saltos de línea a formato MD)
  sanitizeText: (text) => {
    if (text === undefined || text === null) return '';
    return String(text)
      .replace(/"/g, "'")
      .replace(/\\n/g, ' ') // Reemplaza \n literales con espacios
      .replace(/\n/g, ' '); // Reemplaza saltos de línea reales con espacios
  },

  // Capitaliza la primera letra
  capitalize: (str) => str.charAt(0).toUpperCase() + str.slice(1),

  // Procesa texto, elimina números iniciales y espacios extra
  processText: (text) => {
    if (typeof text !== 'string') return '';
    return text.replace(/^\d+\.\s*/, '').trim();
  },

  // Formatea objetos anidados sin saltos de línea extra
  formatNestedContent: (content) => {
    if (!content) return '';
    if (typeof content === 'string') return content;

    if (Array.isArray(content)) {
      return content.map(item => Utils.formatNestedContent(item)).join(' ');
    }

    if (typeof content === 'object') {
      return Object.entries(content)
        .map(([key, value]) => {
          const processedValue = Utils.formatNestedContent(value);
          if (key.match(/^\d+\./)) {
            return processedValue;
          }
          return processedValue;
        })
        .filter(Boolean)
        .join(' ');
    }

    return '';
  },

  // Formatea texto para markdown en ClickUp
  formatForClickUp: (text) => {
    if (!text) return '';
    // Convertir formato markdown específico para ClickUp
    return text
      .replace(/\\n\\n/g, ' ')  // Reemplazar \n\n con espacio
      .replace(/\\n/g, ' ')     // Reemplazar \n con espacio
      .replace(/\*\*/g, '**');  // Mantener negrita
  }
};

// Obtener y procesar datos
const getFieldContent = (data, field) => {
  try {
    const content = data["2. Evaluación de la Llamada"]?.[field];
    return Utils.formatNestedContent(content);
  } catch (e) {
    console.error(`Error processing field ${field}:`, e);
    return '';
  }
};

// Obtener datos de los nodos anteriores
const inputContent = $input.first().json.message.content;
const inputData = {
  tipo_llamada: inputContent["1. Análisis de la Llamada"]["TIPO DE LLAMADA"],
  transcripcion: $('TRANSCRIPCION1').item.json.transcript,
  puntuacion: getFieldContent(inputContent, "PUNTUACION"),
  puntos_fuertes: getFieldContent(inputContent, "PUNTOS FUERTES"),
  puntos_debiles: getFieldContent(inputContent, "PUNTOS DEBILES"),
  recomendaciones: getFieldContent(inputContent, "FEEDBACK"),
  faq_objeciones: getFieldContent(inputContent, "OBJECIONES_Y_FAQ"),
  seguimiento: getFieldContent(inputContent, "PLAN_SEGUIMIENTO"),
  solicitud_referido: inputContent["1. Análisis de la Llamada"]["REFERIDOS"],
  asistente: $('NombreAsesor').first().json.NombreAsesor,
  promesas_vendedor: {
    tiempos: inputContent["1. Análisis de la Llamada"]["PROMESAS Y COMPROMISOS"]["1. Tiempos"],
    deudas: inputContent["1. Análisis de la Llamada"]["PROMESAS Y COMPROMISOS"]["2. Deudas"],
    collections: inputContent["1. Análisis de la Llamada"]["PROMESAS Y COMPROMISOS"]["3. Collections"]
  }
};

// Preparar los campos personalizados
const customFieldsPayload = Object.entries(CUSTOM_FIELDS).map(([key, id]) => {
  let value = inputData[key];

  if (key === 'puntuacion') {
    value = parseFloat(value) || 0;
  } else if (key === 'promesas_vendedor') {
    value = Object.entries(value)
      .map(([tipo, promesa]) => `${Utils.capitalize(tipo)}: ${promesa}`)
      .join(' ');
  } else {
    value = Utils.sanitizeText(value);
  }

  return { id, value };
});

// Crear la descripción en formato para ClickUp
const description = Object.entries(inputData)
  .map(([key, value]) => {
    const formattedKey = Utils.capitalize(key.replace(/_/g, ' '));
    let formattedValue;

    if (key === 'promesas_vendedor') {
      formattedValue = Object.entries(value)
        .map(([tipo, promesa]) => `${Utils.capitalize(tipo)}: ${promesa}`)
        .join(' ');
    } else {
      formattedValue = Utils.formatForClickUp(Utils.sanitizeText(value));
    }

    return `**${formattedKey}:** ${formattedValue}`;
  })
  .join(' ');

// Retornar el payload final
return [{
  json: {
    list_id: "901109287295",
    name: `[${inputData.tipo_llamada}] Resumen de llamada`,
    description,
    custom_fields: customFieldsPayload
  }
}];

